using UnityEngine;
using UnityEngine.Purchasing;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int baseDamage = 10;
    public int weaponLevel = 1;
    public float damageMultiplier = 1f;

    public int CalculateDamage()
    {
        return Mathf.Max(1, Mathf.RoundToInt(baseDamage * weaponLevel * damageMultiplier));
    }

    public void TakeDamage(int amount)
    {
        currentHealth = Mathf.Max(0, currentHealth - Mathf.Max(0, amount));
    }

    public void Heal(int amount)
    {
        currentHealth = Mathf.Min(maxHealth, currentHealth + Mathf.Max(0, amount));
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool SpendCurrency(int amount)
    {
        amount = Mathf.Max(0, amount);
        if (currency < amount) return false;
        currency -= amount;
        return true;
    }
}

public class Enemy : MonoBehaviour
{
    public int maxHealth = 50;
    public int currentHealth = 50;

    public void TakeDamage(int amount)
    {
        currentHealth = Mathf.Max(0, currentHealth - Mathf.Max(0, amount));
        if (currentHealth == 0)
        {
            Destroy(gameObject);
        }
    }
}

public class PlayerCombat : MonoBehaviour
{
    public PlayerStats playerStats;

    public void Attack(Enemy enemy)
    {
        if (enemy == null || playerStats == null) return;
        int damage = playerStats.CalculateDamage();
        enemy.TakeDamage(damage);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;

    public int healthUpgradeBasePrice = 100;
    public int weaponUpgradeBasePrice = 150;
    public int healPrice = 25;
    public int healthUpgradeStep = 20;
    public int weaponUpgradeStep = 1;
    public int healAmount = 25;

    public int GetHealthUpgradePrice()
    {
        if (playerStats == null) return 0;
        return healthUpgradeBasePrice * Mathf.Max(1, playerStats.maxHealth / 100);
    }

    public int GetWeaponUpgradePrice()
    {
        if (playerStats == null) return 0;
        return weaponUpgradeBasePrice * playerStats.weaponLevel;
    }

    public bool BuyHealthUpgrade()
    {
        if (playerStats == null) return false;

        int price = GetHealthUpgradePrice();
        if (!playerStats.SpendCurrency(price)) return false;

        playerStats.maxHealth += healthUpgradeStep;
        playerStats.currentHealth = playerStats.maxHealth;
        return true;
    }

    public bool BuyWeaponUpgrade()
    {
        if (playerStats == null) return false;

        int price = GetWeaponUpgradePrice();
        if (!playerStats.SpendCurrency(price)) return false;

        playerStats.weaponLevel += weaponUpgradeStep;
        return true;
    }

    public bool BuyHeal()
    {
        if (playerStats == null) return false;

        if (!playerStats.SpendCurrency(healPrice)) return false;

        playerStats.Heal(healAmount);
        return true;
    }
}

public class MobileIAPCurrency : MonoBehaviour, IStoreListener
{
    public PlayerStats playerStats;

    public string currencyPackSmall = "currency_small";
    public string currencyPackMedium = "currency_medium";
    public string currencyPackLarge = "currency_large";

    public int currencyPackSmallAmount = 100;
    public int currencyPackMediumAmount = 500;
    public int currencyPackLargeAmount = 1200;

    private IStoreController storeController;
    private IExtensionProvider extensionProvider;

    public void Start()
    {
        if (storeController == null)
        {
            InitializePurchasing();
        }
    }

    public void InitializePurchasing()
    {
        if (IsInitialized()) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        builder.AddProduct(currencyPackSmall, ProductType.Consumable);
        builder.AddProduct(currencyPackMedium, ProductType.Consumable);
        builder.AddProduct(currencyPackLarge, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    private bool IsInitialized()
    {
        return storeController != null && extensionProvider != null;
    }

    public void BuySmallPack()
    {
        BuyProductID(currencyPackSmall);
    }

    public void BuyMediumPack()
    {
        BuyProductID(currencyPackMedium);
    }

    public void BuyLargePack()
    {
        BuyProductID(currencyPackLarge);
    }

    private void BuyProductID(string productId)
    {
        if (!IsInitialized()) return;

        Product product = storeController.products.WithID(productId);
        if (product != null && product.availableToPurchase)
        {
            storeController.InitiatePurchase(product);
        }
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        storeController = controller;
        extensionProvider = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error)
    {
    }

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs args)
    {
        if (playerStats == null) return PurchaseProcessingResult.Complete;

        if (args.purchasedProduct.definition.id == currencyPackSmall)
        {
            playerStats.AddCurrency(currencyPackSmallAmount);
        }
        else if (args.purchasedProduct.definition.id == currencyPackMedium)
        {
            playerStats.AddCurrency(currencyPackMediumAmount);
        }
        else if (args.purchasedProduct.definition.id == currencyPackLarge)
        {
            playerStats.AddCurrency(currencyPackLargeAmount);
        }

        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason)
    {
    }
}